#!/usr/bin/env python
import os
import sys
import shutil
import tarfile
import zipfile
import subprocess
import argparse
import tempfile
from pathlib import Path

def create_tar_gz(source_dir, output_path):
    with tarfile.open(output_path, "w:gz") as tar:
        tar.add(source_dir, arcname=os.path.basename(source_dir))

def create_tar_bz2(source_dir, output_path):
    with tarfile.open(output_path, "w:bz2") as tar:
        tar.add(source_dir, arcname=os.path.basename(source_dir))

def create_zip(source_dir, output_path):
    with zipfile.ZipFile(output_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
        for root, dirs, files in os.walk(source_dir):
            for file in files:
                file_path = os.path.join(root, file)
                arc_path = os.path.relpath(file_path, source_dir)
                zipf.write(file_path, arc_path)

def create_7z(source_dir, output_path):
    try:
        subprocess.run(['7z', 'a', '-y', output_path, source_dir], check=True, 
                      stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
    except (subprocess.CalledProcessError, FileNotFoundError):
        raise RuntimeError("7z command not found or failed")

def validate_path(path):
    """Validate that path exists and is accessible"""
    if not os.path.exists(path):
        raise ValueError(f"Path does not exist: {path}")
    
    if not os.access(path, os.R_OK):
        raise ValueError(f"Path is not readable: {path}")
    
    # Security check: ensure path is within user's home directory
    home = os.path.expanduser("~")
    if not os.path.abspath(path).startswith(os.path.abspath(home)):
        raise ValueError("Path must be within user's home directory")

def main():
    parser = argparse.ArgumentParser(description='Create compressed backup of user directories')
    parser.add_argument('directory', help='Directory to backup')
    parser.add_argument('format', choices=['tar.gz', 'tar.bz2', 'zip', '7z'], 
                       help='Compression format')
    parser.add_argument('-o', '--output', help='Output file path (optional)')
    
    args = parser.parse_args()
    
    try:
        validate_path(args.directory)
        
        if args.output:
            output_path = args.output
        else:
            basename = os.path.basename(os.path.normpath(args.directory))
            output_path = f"{basename}.{args.format}"
        
        # Security: ensure output path is within current directory
        output_path = os.path.abspath(output_path)
        if not output_path.startswith(os.getcwd()):
            raise ValueError("Output path must be within current directory")
        
        # Create backup
        if args.format == 'tar.gz':
            create_tar_gz(args.directory, output_path)
        elif args.format == 'tar.bz2':
            create_tar_bz2(args.directory, output_path)
        elif args.format == 'zip':
            create_zip(args.directory, output_path)
        elif args.format == '7z':
            create_7z(args.directory, output_path)
        
        print(f"Backup created successfully: {output_path}")
        
    except Exception as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)

if __name__ == "__main__":
    main()